#include <bits/stdc++.h>
using namespace std;
const int maxn=500005;
long long k,qq[maxn],day[maxn],n,d,mid,ans;
int check(int x) {
	for(int i=1; i<=n; i++) {
		day[i]=0;
	}
	long long kx=0,j=0;
	for(int i=1; i<=d; i++) {
		kx=kx>>1;
		while(kx<x) {
			j++;
			kx+=qq[j];
			day[j]=i;
			if(j>n) {
				return 0;
			}
		}
	}
	return 1;
}
int main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n>>d;
	for(int i=1; i<=n; i++) {
		cin>>qq[i];
		k+=qq[i];
	}
	long long l=0,r=k;
	while(l<=r) {
		mid=(l+r)>>1;
		if(!check(mid)) {
			r=mid-1;
		}
		if(check(mid)) {
			l=mid+1;
			ans=mid;
		}
	}
	cout<<ans<<"\n";
	for(int i=1; i<=n; i++) {
		cout<<day[i]<<"\n";
	}
	return 0;
}
